import AppKit

/// The anchor glyph shown beside the app name in the menu header.
///
/// Embedded as a base64-encoded vector PDF rather than shipped as a bundle resource: the app is
/// packaged as a bare executable (see `Scripts/package_app.sh`), so a self-contained asset avoids
/// adding a resource bundle. PDF loads natively via `NSImage` on every supported macOS version,
/// unlike SVG which is unreliable on the macOS 12 deployment target.
enum AnchorAsset {
    static let image: NSImage? = {
        guard let data = Data(base64Encoded: pdfBase64),
              let image = NSImage(data: data) else { return nil }
        return image
    }()

    private static let pdfBase64 = """
    
    """
}
